 1	import { Button, Popper } from '@patternfly/react-core';
 2	import { CogIcon } from '@patternfly/react-icons';
 3	import * as React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	import { useOutsideClickEvent } from '../../utils/outside-hook';
 6	import './table-display-dropdown.css';
 7	import { TableDisplayOptions } from './table-display-options';
 8	
 9	export type Size = 's' | 'm' | 'l';
10	
11	export interface TableDisplayDropdownProps {
12	  size: Size;
13	  setSize: (v: Size) => void;
14	  showDuplicates: boolean;
15	  setShowDuplicates: (showDuplicates: boolean) => void;
16	}
17	
18	export const TableDisplayDropdown: React.FC<TableDisplayDropdownProps> = ({
19	  size,
20	  setSize,
21	  showDuplicates,
22	  setShowDuplicates
23	}) => {
24	  const { t } = useTranslation('plugin__netobserv-plugin');
25	  const containerRef = React.useRef<HTMLDivElement>(null);
26	  const triggerRef = React.useRef<HTMLButtonElement>(null);
27	  const popperRef = React.useRef<HTMLDivElement>(null);
28	  const [isOpen, setOpen] = React.useState<boolean>(false);
29	
30	  const ref = useOutsideClickEvent(() => setOpen(false));
31	
32	  const trigger = React.useCallback(() => {
33	    return (
34	      <Button
35	        ref={triggerRef}
36	        variant="link"
37	        icon={<CogIcon />}
38	        onClick={() => setOpen(!isOpen)}
39	        data-test="display-dropdown-button"
40	      >
41	        {t('Display options')}
42	      </Button>
43	    );
44	  }, [isOpen, t]);
45	
46	  const popper = React.useCallback(() => {
47	    return (
48	      <div id="table-display-popper" ref={popperRef} className="pf-v6-c-menu" role="dialog">
49	        <TableDisplayOptions
50	          size={size}
51	          setSize={setSize}
52	          showDuplicates={showDuplicates}
53	          setShowDuplicates={setShowDuplicates}
54	        />
55	      </div>
56	    );
57	  }, [size, setSize, showDuplicates, setShowDuplicates]);
58	
59	  return (
60	    <div id="display-dropdown-container" data-test="display-dropdown-container" ref={ref}>
61	      <div ref={containerRef}>
62	        <Popper
63	          trigger={trigger()}
64	          triggerRef={triggerRef}
65	          popper={popper()}
66	          popperRef={popperRef}
67	          isVisible={isOpen}
68	          enableFlip={true}
69	          appendTo={containerRef.current || undefined}
70	        />
71	      </div>
72	    </div>
73	  );
74	};
75	
76	export default TableDisplayDropdown;

