 1	import { act, fireEvent, render } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { Size, TableDisplayDropdown } from '../table-display-dropdown';
 5	import { TableDisplayOptions } from '../table-display-options';
 6	
 7	describe('<DisplayDropdown />', () => {
 8	  const props = {
 9	    size: 's' as Size,
10	    setSize: jest.fn(),
11	    showDuplicates: true,
12	    setShowDuplicates: jest.fn()
13	  };
14	
15	  it('should render component', async () => {
16	    const { container } = render(<TableDisplayDropdown {...props} />);
17	    expect(container.querySelector('[data-test="display-dropdown-button"]')).toBeTruthy();
18	  });
19	
20	  it('should setSize on select', async () => {
21	    const { container } = render(<TableDisplayOptions {...props} size="m" />);
22	
23	    await act(async () => {
24	      fireEvent.click(container.querySelector('#size-s')!);
25	    });
26	    expect(props.setSize).toHaveBeenCalledWith('s');
27	
28	    await act(async () => {
29	      fireEvent.click(container.querySelector('#size-l')!);
30	    });
31	    expect(props.setSize).toHaveBeenCalledWith('l');
32	    expect(props.setSize).toHaveBeenCalledTimes(2);
33	  });
34	});

